# Example tilemap file

[properties]
# number of tiles in the map (mandatory)
map_size 25 30
# define the rendering order (background first, then foreground)
# default render_order is file declaration order
render_order layer0 layer1

[table]
# Correspondance table between tiles numbers and textures or animations (must be already loaded when loading tile map)
# <tileref> animated <0|1> <sprite|animation>
     0      animated  0     tile0
     1      animated  0     tile1
     2      animated  0     tile2
     3      animated  0     tile3
     4      animated  0     tile4
     5      animated  0     tile5
     6      animated  0     tile6
     7      animated  0     tile7
     8      animated  0     tile8
     9      animated  0     tile9
     10     animated  0     tile10
     11     animated  0     tile11
     12     animated  0     tile12
     13     animated  0     tile13
     14     animated  0     tile14
     15     animated  0     tile15
     16     animated  0     tile16
     17     animated  0     tile17
     18     animated  0     tile18
     19     animated  0     tile19
     20     animated  0     tile20
     21     animated  0     tile21
     22     animated  0     tile22
     23     animated  0     tile23
     24     animated  0     tile24
     25     animated  0     tile25
     26     animated  0     tile26


[layer]
# layer name is mandatory
layer_name layer0
# Number of lines and columns must match the tiles_number property.
# Multiple spaces or tabs characters can be used in between numbers
